challenge.solution:
class Transaction:
  def __init__(self, data):
    self.data = data
  def __enter__(self):
    self.copy = self.data.copy()
    return self.copy
  def __exit__(self, exc_type, exc_val, tb):
    if exc_type is None:
      self.data.update(self.copy)
